`;

const TechStackPreview = styled.div`
  background: #f8fafc;
  border-radius: 0.75rem;
  padding: 1rem;
  margin-top: 1rem;
  border: 1px solid #e2e8f0;
`;

const TechStackItem = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.5rem 0;
  border-bottom: 1px solid #e2e8f0;
  
  &:last-child {
    border-bottom: none;
  }
`;

const TechStackLabel = styled.span`
  font-weight: 500;
  color: #1e293b;
  text-transform: capitalize;
`;

const TechStackValue = styled.span`
  color: #667eea;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 0.5rem;
`;

function Builder() {
  const navigate = useNavigate();
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [chatMessages, setChatMessages] = useState([
    {
      type: 'ai',
      content: '👋 Hi! I\'m your AI App Builder assistant. Tell me what application you want to build, or choose a template to get started!'
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentProject, setCurrentProject] = useState(null);
  const [buildSteps, setBuildSteps] = useState([
    { id: 1, name: 'Analyze Requirements', status: 'pending' },
    { id: 2, name: 'Generate Code', status: 'pending' },
    { id: 3, name: 'Setup Database', status: 'pending' },
    { id: 4, name: 'Configure APIs', status: 'pending' },
    { id: 5, name: 'Ready to Deploy', status: 'pending' }
  ]);
  
  // New framework-related state
  const [showFrameworkSelector, setShowFrameworkSelector] = useState(false);
  const [selectedFrameworks, setSelectedFrameworks] = useState({
    frontend: 'react',
    backend: 'fastapi',
    database: 'mysql'
  });
  const [supportedFrameworks, setSupportedFrameworks] = useState(null);
  const [frameworkRecommendations, setFrameworkRecommendations] = useState(null);
  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
  
  // Real-time creation state
  const [realtimeSession, setRealtimeSession] = useState(null);
  const [realtimeProgress, setRealtimeProgress] = useState(null);
  const [isRealtimeBuilding, setIsRealtimeBuilding] = useState(false);
  const [websocketConnected, setWebsocketConnected] = useState(false);

  // Load supported frameworks on component mount
  useEffect(() => {
    const loadFrameworks = async () => {
      try {
        const response = await frameworkService.getSupportedFrameworks();
        setSupportedFrameworks(response.frameworks);
      } catch (error) {
        console.error('Failed to load frameworks:', error);
      }
    };
    
    loadFrameworks();
    
    // Cleanup WebSocket connection on unmount
    return () => {
      if (realtimeProjectService.getIsConnected()) {
        realtimeProjectService.disconnect();
      }
    };
  }, []);

  const templates = [
    {
      id: 'dashboard',
      name: 'Analytics Dashboard',
      description: 'Business intelligence dashboard with charts, KPIs, and real-time data visualization',
      icon: BarChart3,
      features: ['Charts & Graphs', 'Real-time Data', 'User Management', 'Export Reports']
    },
    {
      id: 'ecommerce',
      name: 'E-commerce Store',
      description: 'Complete online store with product management, cart, and payment processing',
      icon: ShoppingCart,
      features: ['Product Catalog', 'Shopping Cart', 'Payment Gateway', 'Order Management']
    },
    {
      id: 'blog',
      name: 'Blog & CMS',
      description: 'Content management system with rich editor, comments, and SEO optimization',
      icon: FileText,
      features: ['Rich Text Editor', 'Comment System', 'SEO Tools', 'Media Management']
    },
    {
      id: 'chat',
      name: 'Chat Application',
      description: 'Real-time messaging platform with rooms, file sharing, and notifications',
      icon: MessageCircle,
      features: ['Real-time Chat', 'File Sharing', 'Chat Rooms', 'Push Notifications']
    },
    {
      id: 'crm',
      name: 'CRM System',
      description: 'Customer relationship management with contacts, deals, and sales pipeline',
      icon: Users,
      features: ['Contact Management', 'Sales Pipeline', 'Task Tracking', 'Reports']
    },
    {
      id: 'saas',
      name: 'SaaS Platform',
      description: 'Multi-tenant SaaS application with subscriptions and user management',
      icon: Cloud,
      features: ['Multi-tenancy', 'Subscription Billing', 'API Management', 'Analytics']
    }
  ];

  const examplePrompts = [
    "Build a task management app with team collaboration",
    "Create a social media platform with posts and likes",
    "Build an inventory management system for warehouses",
    "Create a booking system for appointments",
    "Build a learning management system for courses"
  ];

  const handleSendMessage = async () => {
    if (!inputMessage.trim() || isGenerating) return;

    const userMessage = inputMessage.trim();
    setInputMessage('');
    
    // Add user message
    setChatMessages(prev => [...prev, { type: 'user', content: userMessage }]);
    
    setIsGenerating(true);
    
    try {
      // Simulate AI processing
      setTimeout(() => {
        const aiResponse = generateAIResponse(userMessage);
        setChatMessages(prev => [...prev, { type: 'ai', content: aiResponse }]);
        
        // Start building process if user requested an app
        if (userMessage.toLowerCase().includes('build') || userMessage.toLowerCase().includes('create')) {
          startBuildProcess(userMessage);
        }
        
        setIsGenerating(false);
      }, 1500);
      
    } catch (error) {
      toast.error('Failed to process your request');
      setIsGenerating(false);
    }
  };

  const generateAIResponse = (message) => {
    const responses = [
      `Great idea! I'll help you build a ${extractAppType(message)}. Let me analyze your requirements and generate the complete application with React frontend, FastAPI backend, and MySQL database.`,
      `Perfect! I understand you want to create a ${extractAppType(message)}. I'll generate all the necessary components including authentication, database models, API endpoints, and a modern React interface.`,
      `Excellent choice! Building a ${extractAppType(message)} is a great project. I'll create a production-ready application with all the features you need, including proper security, responsive design, and deployment configurations.`
    ];
    
    return responses[Math.floor(Math.random() * responses.length)];
  };

  const extractAppType = (message) => {
    const types = {
      'dashboard': 'analytics dashboard',
      'ecommerce': 'e-commerce platform',
      'blog': 'blog platform',
      'chat': 'chat application',
      'crm': 'CRM system',
      'task': 'task management app',
      'social': 'social media platform',
      'inventory': 'inventory management system',
      'booking': 'booking system',
      'learning': 'learning management system'
    };
    
    for (const [key, value] of Object.entries(types)) {
      if (message.toLowerCase().includes(key)) {
        return value;
      }
    }
    
    return 'custom application';
  };

  const startBuildProcess = (description) => {
    setCurrentProject({ 
      name: extractAppType(description),
      description,
      startTime: new Date()
    });
    
    // Simulate build steps
    let currentStep = 0;
    const interval = setInterval(() => {
      setBuildSteps(prev => 
        prev.map((step, index) => {
          if (index === currentStep) {
            return { ...step, status: 'active' };
          } else if (index < currentStep) {
            return { ...step, status: 'completed' };
          }
          return step;
        })
      );
      
      currentStep++;
      if (currentStep >= buildSteps.length) {
        clearInterval(interval);
        setBuildSteps(prev => 
          prev.map(step => ({ ...step, status: 'completed' }))
        );
        toast.success('🎉 Application generated successfully!');
      }
    }, 2000);
  };

  const handleTemplateSelect = (template) => {
    setSelectedTemplate(template);
    const message = `Build a ${template.name.toLowerCase()} with the following features: ${template.features.join(', ')}`;
    setInputMessage(message);
  };

  const handleBuildFromTemplate = () => {
    if (!selectedTemplate) return;
    
    const message = `Build a ${selectedTemplate.name.toLowerCase()} - ${selectedTemplate.description}`;
    setChatMessages(prev => [...prev, { type: 'user', content: message }]);
    
    setIsGenerating(true);
    setTimeout(() => {
      setChatMessages(prev => [...prev, { 
        type: 'ai', 
        content: `Perfect! I'll build a ${selectedTemplate.name} for you. This will include ${selectedTemplate.features.join(', ')} and all the necessary backend infrastructure.`
      }]);
      startBuildProcess(message);
      setIsGenerating(false);
    }, 1000);
  };

  const handleDeployApp = () => {
    if (currentProject) {
      toast.success('Redirecting to deployment...');
      navigate('/deploy');
    }
  };

  // Framework selection handlers
  const handleFrameworkSelect = (category, framework) => {
    setSelectedFrameworks(prev => ({
      ...prev,
      [category]: framework
    }));
  };

  const getFrameworkRecommendations = async (templateId) => {
    if (!selectedTemplate) return;
    
    try {
      const analysis = {
        project_type: templateId,
        features: selectedTemplate.features
      };
      
      const response = await frameworkService.getFrameworkRecommendations(analysis);
      setFrameworkRecommendations(response.recommendations);
    } catch (error) {
      console.error('Failed to get recommendations:', error);
    }
  };

  const handleBuildWithFrameworks = async () => {
    if (!selectedTemplate) {
      toast.error('Please select a template first');
      return;
    }
    
    const projectName = `${selectedTemplate.name.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}`;
    
    try {
      setIsGenerating(true);
      
      const analysis = {
        project_type: selectedTemplate.id,
        features: selectedTemplate.features,
        description: selectedTemplate.description
      };
      
      const projectData = {
        name: projectName,
        analysis,
        frontend_framework: selectedFrameworks.frontend,
        backend_framework: selectedFrameworks.backend,
        database: selectedFrameworks.database
      };
      
      const response = await frameworkService.generateProjectWithCustomStack(projectData);
      
      if (response.success) {
        toast.success(response.message);
        setChatMessages(prev => [...prev, {
          type: 'ai',
          content: `🎉 Successfully generated ${response.project.name} using ${selectedFrameworks.frontend} + ${selectedFrameworks.backend} + ${selectedFrameworks.database}!`
        }]);
        
        setCurrentProject(response.project);
        startBuildProcess(`Generated ${selectedTemplate.name}`);
      }
      
    } catch (error) {
      toast.error('Failed to generate project');
      console.error('Generation error:', error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <Container>
      <Header>
        <Title>
          <Bot size={40} style={{ verticalAlign: 'middle', marginRight: '10px' }} />
          AI Application Builder
          <Sparkles size={30} style={{ marginLeft: '10px', verticalAlign: 'middle' }} />
        </Title>
        <Subtitle>
          Transform your ideas into production-ready applications using natural language. 
          Build unlimited React + FastAPI + MySQL applications with AI assistance.
        </Subtitle>
      </Header>

      <MainContent>
        <div>
          <BuilderSection>
            <SectionTitle>
              <MessageSquare size={24} />
              Chat with AI Builder
            </SectionTitle>
            
            <ChatInterface>
              <ChatMessages>
                {chatMessages.map((message, index) => (
                  <Message key={index} className={message.type}>
                    <div className="content">{message.content}</div>
                  </Message>
                ))}
                {isGenerating && (
                  <Message className="ai">
                    <div className="content">
                      <LoadingSpinner>
                        <Loader size={16} />
                      </LoadingSpinner>
                      <span style={{ marginLeft: '8px' }}>AI is thinking...</span>
                    </div>
                  </Message>
                )}
              </ChatMessages>
              
              <ChatInput>
                <Input
                  type="text"
                  placeholder="Describe the application you want to build..."
                  value={inputMessage}
                  onChange={(e) => setInputMessage(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                />
                <SendButton onClick={handleSendMessage} disabled={isGenerating}>
                  <Send size={16} />
                  Send
                </SendButton>
              </ChatInput>
            </ChatInterface>

            <div style={{ marginTop: '1rem' }}>
              <h4 style={{ marginBottom: '0.5rem', color: '#64748b', fontSize: '0.875rem' }}>
                💡 Try these examples:
              </h4>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
                {examplePrompts.map((prompt, index) => (
                  <button
                    key={index}
                    onClick={() => setInputMessage(prompt)}
                    style={{
                      background: '#f1f5f9',
                      border: '1px solid #e2e8f0',
                      borderRadius: '1rem',
                      padding: '0.5rem 1rem',
                      fontSize: '0.875rem',
                      color: '#64748b',
                      cursor: 'pointer',
                      transition: 'all 0.2s ease'
                    }}
                    onMouseOver={(e) => {
                      e.target.style.background = '#667eea';
                      e.target.style.color = 'white';
                    }}
                    onMouseOut={(e) => {
                      e.target.style.background = '#f1f5f9';
                      e.target.style.color = '#64748b';
                    }}
                  >
                    {prompt}
                  </button>
                ))}
              </div>
            </div>
          </BuilderSection>

          <BuilderSection style={{ marginTop: '2rem' }}>
            <SectionTitle>
              <Template size={24} />
              Quick Start Templates
            </SectionTitle>
            
            <TemplateGrid>
              {templates.map((template) => (
                <TemplateCard
                  key={template.id}
                  selected={selectedTemplate?.id === template.id}
                  onClick={() => handleTemplateSelect(template)}
                >
                  <TemplateIcon>
                    <template.icon size={24} />
                  </TemplateIcon>
                  <TemplateName>{template.name}</TemplateName>
                  <TemplateDescription>{template.description}</TemplateDescription>
                  <div style={{ marginTop: '1rem' }}>
                    {template.features.map((feature, index) => (
                      <span
                        key={index}
                        style={{
                          display: 'inline-block',
                          background: '#f1f5f9',
                          color: '#64748b',
                          padding: '0.25rem 0.5rem',
                          borderRadius: '0.5rem',
                          fontSize: '0.75rem',
                          margin: '0.125rem',
                        }}
                      >
                        {feature}
                      </span>
                    ))}
                  </div>
                </TemplateCard>
              ))}
            </TemplateGrid>

            {selectedTemplate && (
              <>
                <FrameworkSection>
                  <SectionTitle>
                    <Cpu size={20} />
                    Technology Stack
                    {frameworkRecommendations && (
                      <RecommendationBadge>
                        <Star size={12} />
                        AI Recommended
                      </RecommendationBadge>
                    )}
                  </SectionTitle>
                  
                  <AdvancedToggle 
                    onClick={() => {
                      setShowAdvancedOptions(!showAdvancedOptions);
                      if (!showAdvancedOptions) {
                        getFrameworkRecommendations(selectedTemplate.id);
                      }
                    }}
                  >
                    <Settings size={16} />
                    {showAdvancedOptions ? 'Use Default Stack' : 'Advanced Framework Selection'}
                    <ChevronDown 
                      size={16} 
                      style={{ 
                        transform: showAdvancedOptions ? 'rotate(180deg)' : 'rotate(0deg)',
                        transition: 'transform 0.3s ease'
                      }} 
                    />
                  </AdvancedToggle>
                  
                  {showAdvancedOptions && supportedFrameworks && (
                    <>
                      {['frontend', 'backend', 'database'].map(category => (
                        <div key={category} style={{ marginBottom: '1.5rem' }}>
                          <h4 style={{ 
                            fontSize: '1rem', 
                            fontWeight: '600', 
                            color: '#1e293b', 
                            marginBottom: '0.75rem',
                            textTransform: 'capitalize'
                          }}>
                            {category} Framework
                          </h4>
                          
                          <FrameworkGrid>
                            {supportedFrameworks[category] && Object.entries(supportedFrameworks[category]).map(([key, framework]) => (
                              <FrameworkCard
                                key={key}
                                selected={selectedFrameworks[category] === key}
                                onClick={() => handleFrameworkSelect(category, key)}
                              >
                                <FrameworkHeader>
                                  <FrameworkIcon>{framework.icon || '🔧'}</FrameworkIcon>
                                  <FrameworkName>{framework.name}</FrameworkName>
                                  {frameworkRecommendations?.primary?.[category] === key && (
                                    <RecommendationBadge>
                                      <Star size={10} />
                                      Recommended
                                    </RecommendationBadge>
                                  )}
                                </FrameworkHeader>
                                <FrameworkDescription>{framework.description}</FrameworkDescription>
                              </FrameworkCard>
                            ))}
                          </FrameworkGrid>
                        </div>
                      ))}
                      
                      <TechStackPreview>
                        <h4 style={{ fontSize: '1rem', fontWeight: '600', color: '#1e293b', marginBottom: '0.75rem' }}>
                          Selected Technology Stack
                        </h4>
                        {Object.entries(selectedFrameworks).map(([category, framework]) => (
                          <TechStackItem key={category}>
                            <TechStackLabel>{category}:</TechStackLabel>
                            <TechStackValue>
                              {supportedFrameworks[category]?.[framework]?.icon || '🔧'}
                              {supportedFrameworks[category]?.[framework]?.name || framework}
                            </TechStackValue>
                          </TechStackItem>
                        ))}
                      </TechStackPreview>
                    </>
                  )}
                </FrameworkSection>
                
                <ActionButton 
                  onClick={showAdvancedOptions ? handleBuildWithFrameworks : handleBuildFromTemplate}
                  disabled={isGenerating}
                >
                  {isGenerating ? (
                    <>
                      <LoadingSpinner><Loader size={20} /></LoadingSpinner>
                      Generating...
                    </>
                  ) : (
                    <>
                      <Rocket size={20} />
                      Build {selectedTemplate.name}
                      {showAdvancedOptions && (
                        <span style={{ fontSize: '0.875rem', opacity: 0.8 }}>
                          ({selectedFrameworks.frontend} + {selectedFrameworks.backend} + {selectedFrameworks.database})
                        </span>
                      )}
                    </>
                  )}
                </ActionButton>
              </>
            )}
          </BuilderSection>
        </div>

        <Sidebar>
          <ProgressCard>
            <SectionTitle style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>
              <Cog size={20} />
              Build Progress
            </SectionTitle>
            
            {buildSteps.map((step) => (
              <ProgressStep key={step.id} className={step.status}>
                <StepIcon className={step.status}>
                  {step.status === 'completed' ? (
                    <CheckCircle size={16} />
                  ) : step.status === 'active' ? (
                    <LoadingSpinner>
                      <Loader size={16} />
                    </LoadingSpinner>
                  ) : (
                    step.id
                  )}
                </StepIcon>
                <span>{step.name}</span>
              </ProgressStep>
            ))}

            {currentProject && buildSteps.every(step => step.status === 'completed') && (
              <ActionButton onClick={handleDeployApp} style={{ marginTop: '1rem' }}>
                <Rocket size={20} />
                Deploy Application
              </ActionButton>
            )}
          </ProgressCard>

          <ProgressCard>
            <SectionTitle style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>
              <Zap size={20} />
              Recent Projects
            </SectionTitle>
            
            <div style={{ color: '#64748b', textAlign: 'center', padding: '2rem 0' }}>
              {currentProject ? (
                <div>
                  <h4 style={{ color: '#1e293b', marginBottom: '0.5rem' }}>
                    {currentProject.name}
                  </h4>
                  <p style={{ fontSize: '0.875rem' }}>
                    Started {currentProject.startTime.toLocaleTimeString()}
                  </p>
                </div>
              ) : (
                <p>No projects yet. Start building your first application!</p>
              )}
            </div>
          </ProgressCard>
        </Sidebar>
      </MainContent>
    </Container>
  );
}

export default Builder;
